import React, { useState, useEffect } from 'react';
import useGetDate from '../Hooks/useGetDate';
import useGetSingleAPOD from '../Hooks/useGetSingleAPOD';

const Single = () => {

  const [apod, setApod] = useState(null);
  const [err, setErr] = useState(null);

  let date = new Date();
  const today = useGetDate(date);
  const data = useGetSingleAPOD(today);

  useEffect(() => {

    if (data) {
      if (data.error) {
        setErr(data);
      } else {
        setApod(data);
      }
    }

  }, [data]);

  return (
    <div className='single-div'>
      <header className='single-header'>
        <h1>Single APOD</h1>
        <p>Select a single date or scroll with the buttons</p>
      </header>
      <div className="single-form-wrap">
          <form>
            <div className="start-container">
              <label htmlFor="start">Your date 
              (earliest date: 06-16-1995): </label>
              <input type="date" id="start" name="apod-start" min="1995-06-16" max={today} />
            </div>   

            <button className="update-btn" onClick={getPictures}>Update pictures</button>
          </form>
        </div>
      {/* <div className="test">
        {err 
        ? err.error
        : 'Loading...'
      }
      </div> */}
    </div>
  )
}

export default Single
